functions.example_code:
-- 统计总行数
SELECT COUNT(*) AS total FROM users;

-- 统计非空城市数
SELECT COUNT(city) AS has_city FROM users;

-- 统计去重城市数
SELECT COUNT(DISTINCT city) AS unique_cities FROM users;

-- 计算所有订单的总金额
SELECT SUM(amount) AS total_amount FROM orders;

-- 按用户分组求和
SELECT user_id, SUM(amount) AS total_spent
FROM orders GROUP BY user_id;

-- 计算所有订单的平均金额
SELECT AVG(amount) AS avg_amount FROM orders;

-- 保留两位小数
SELECT ROUND(AVG(amount), 2) AS avg_amount FROM orders;

-- 查询最高分
SELECT MAX(score) AS top_score FROM students;

-- 按班级分组取最高分
SELECT class, MAX(score) AS top_score
FROM students GROUP BY class;

-- 估算 UV（独立访客数）
SELECT NDV(user_id) AS approx_uv FROM page_views;

-- 估算每个页面的独立访客
SELECT page_url, NDV(user_id) AS approx_visitors
FROM page_views GROUP BY page_url;

-- 将每个城市的用户名列在一起
SELECT city, GROUP_CONCAT(name) AS users
FROM users GROUP BY city;

-- 指定分隔符
SELECT city, GROUP_CONCAT(name, ' | ') AS users
FROM users GROUP BY city;

-- 从第 3 位开始取 2 个字符
SELECT SUBSTR('abcdef', 3, 2) AS result;
-- 结果: cd

-- 取今天日期
SELECT CURRENT_DATE() AS today;

-- 用作过滤
SELECT * FROM orders WHERE order_date = CURRENT_DATE();

-- 取整
SELECT ROUND(12.7) AS r;

-- 保留两位小数
SELECT ROUND(3.14159, 2) AS r;

-- 字符串转整数
SELECT CAST('123' AS INT) AS num;

-- 字符串转时间戳
SELECT CAST('2024-01-15' AS TIMESTAMP) AS dt;

-- 取邮箱后缀
SELECT STRRIGHT(email, 4) AS suffix FROM users;
-- 例如 'alice@example.com' → '.com'
